// 1. Hacemos la petición a la API de la UNLP
const response = await this.helpers.httpRequest({
    method: 'GET',
    url: 'https://gestionapp.info.unlp.edu.ar/api/CALENDARIO_ACADEMICO',
    json: true
});

// 2. Función para limpiar HTML (quita tags y espacios extra)
function cleanHtml(text) {
    if (!text) return '';
    // Reemplaza cualquier tag HTML (<...>) por un salto de línea
    let clean = text.replace(/<[^>]+>/g, '\n');
    // Reemplaza múltiples espacios/saltos por uno solo
    clean = clean.replace(/\s+/g, ' ')
    .replace(/&aacute;/g,'á')
    .replace(/&eacute;/g,'é')
    .replace(/&iacute;/g,'í')
    .replace(/&oacute;/g,'ó')
    .replace(/&uacute;/g,'ú')
    .replace(/&Aacute;/g,'Á')
    .replace(/&Eacute;/g,'É')
    .replace(/&Iacute;/g,'Í')
    .replace(/&Oacute;/g,'Ó')
    .replace(/&Uacute;/g,'Ú')

      .trim();
    return clean;
}

// 3. Procesamos los datos para reducir tamaño
const cleanData = response.map(item => {
    return {
        calendario: item.nombre,
        contenido: cleanHtml(item.contenido)
    };
});

// 4. 🔥 CORRECCIÓN: Convertimos el objeto a TEXTO (String) para que el Agente lo entienda
return JSON.stringify(cleanData);

// 1. PETICIÓN A LA API
const response = await this.helpers.httpRequest({
  method: 'GET',
  url: 'https://gestiondocente.info.unlp.edu.ar/api/v2/materias.json',
  json: true
});

// 2. EXTRAER MATERIAS
const materias = response._embedded?.materias || [];

if (materias.length === 0) {
    return "No se pudo obtener la lista de materias.";
}

// 3. MAPEAR CON SLUG
const materiasConSlug = materias.map(m => ({
    nombre: m.nombre?.trim() || "Sin nombre",
    slug: m.slug || m._links?.self?.href?.split('/').pop() || ""
})).filter(m => m.nombre !== "Sin nombre" && m.slug);

// 4. FUNCIÓN NORMALIZAR AGRESIVA
function normalizarAgresivo(texto) {
    return texto
        .toLowerCase()
        // Quitar tildes
        .normalize("NFD")
        .replace(/[\u0300-\u036f]/g, "")
        // Singular/Plural: quitar 's' al final de palabras
        .replace(/s\b/g, "")
        // Quitar artículos y preposiciones comunes
        .replace(/\b(de|a|la|el|los|las|y|en)\b/g, "")
        // Quitar espacios múltiples
        .replace(/\s+/g, " ")
        .trim();
}

// 5. FUNCIÓN DE SIMILITUD
function calcularSimilitud(busqueda, nombreMateria) {
    const norm1 = normalizarAgresivo(busqueda);
    const norm2 = normalizarAgresivo(nombreMateria);

    // Si una es substring de la otra, es muy similar
    if (norm1.includes(norm2) || norm2.includes(norm1)) {
        return 0.95;
    }

    // Calcular palabras en común
    const palabras1 = norm1.split(" ").filter(p => p.length > 2);
    const palabras2 = norm2.split(" ").filter(p => p.length > 2);

    if (palabras1.length === 0 || palabras2.length === 0) return 0;

    const palabrasComunes = palabras1.filter(p1 => 
        palabras2.some(p2 => p1.includes(p2) || p2.includes(p1))
    ).length;

    return palabrasComunes / Math.max(palabras1.length, palabras2.length);
}

// 6. FILTRAR SI HAY BÚSQUEDA
const busqueda = (query?.busqueda || "").toLowerCase().trim();

let materiasFinales = materiasConSlug;

if (busqueda) {
    // Calcular similitud para cada materia
    const materiasConScore = materiasConSlug.map(m => ({
        ...m,
        score: calcularSimilitud(busqueda, m.nombre)
    }));

    // Ordenar por similitud descendente
    materiasConScore.sort((a, b) => b.score - a.score);

    // Filtrar candidatos con score > 0.5 (50% de similitud)
    materiasFinales = materiasConScore.filter(m => m.score > 0.5);

    if (materiasFinales.length === 0) {
        // Si no hay coincidencias con fuzzy, intentar búsqueda simple
        const normalizar = (texto) => texto
            .toLowerCase()
            .normalize("NFD")
            .replace(/[\u0300-\u036f]/g, "");

        const busquedaNormalizada = normalizar(busqueda);

        materiasFinales = materiasConSlug.filter(m => 
            normalizar(m.nombre).includes(busquedaNormalizada)
        );

        if (materiasFinales.length === 0) {
            return `❌ No encontré materias que coincidan con "${query.busqueda}". Intenta con otro término.`;
        }
    }

    // Quitar el campo 'score' antes de devolver
    materiasFinales = materiasFinales.map(m => ({
        nombre: m.nombre,
        slug: m.slug
    }));
}

// 7. ORDENAR (si no hay búsqueda, alfabético; si hay búsqueda, ya está ordenado por score)
if (!busqueda) {
    materiasFinales.sort((a, b) => a.nombre.localeCompare(b.nombre));
}

// 8. LIMITAR A 20 SI NO HAY FILTRO
const limite = busqueda ? Math.min(materiasFinales.length, 10) : 20;
const materiasLimitadas = materiasFinales.slice(0, limite);

// 9. RETORNAR
return JSON.stringify({
    total: materiasFinales.length,
    mostrando: materiasLimitadas.length,
    materias: materiasLimitadas,
    nota: busqueda 
        ? `Resultados para "${query.busqueda}" (mostrando ${materiasLimitadas.length} más relevantes)` 
        : "Mostrando primeras 20 materias. Usa 'busqueda' para filtrar."
});

