// 1. OBTENER PARÁMETROS
const busquedaCarrera = (query?.carrera || "").toLowerCase().trim();
const busquedaMateria = (query?.materia || "").toLowerCase().trim();

// 2. PETICIÓN AL ENDPOINT
const response = await this.helpers.httpRequest({
  method: 'GET',
  url: 'https://gestionapp.info.unlp.edu.ar/api/PLANES_ESTUDIOS',
  json: true
});

const todosLosPlanes = Array.isArray(response) ? response : (response.planes || []);

// 3. FUNCIÓN NORMALIZAR
function normalizar(texto) {
    return texto
        .toLowerCase()
        .normalize("NFD")
        .replace(/[\u0300-\u036f]/g, "");
}

// 4. FUNCIÓN LIMPIAR TEXTO
function limpiarTexto(html) {
    if (!html) return "";
    return html
        .replace(/<[^>]+>/g, ' ')
        .replace(/&nbsp;/g, ' ')
        .replace(/&aacute;/g, 'á')
        .replace(/&eacute;/g, 'é')
        .replace(/&iacute;/g, 'í')
        .replace(/&oacute;/g, 'ó')
        .replace(/&uacute;/g, 'ú')
        .replace(/&ntilde;/g, 'ñ')
        .replace(/&Ntilde;/g, 'Ñ')
        .replace(/\s+/g, ' ')
        .trim();
}

// 5. PARSEAR PLAN Y CREAR ÍNDICE DE MATERIAS
function parsearPlanHTML(plan) {
    const html = plan.contenido || "";
    const materias = [];

    // Regex para capturar filas: código, nombre, correlativas
    const regex = /<tr[^>]*>\s*<td[^>]*>([^<]+)<\/td>\s*<td[^>]*>([^<]+)<\/td>\s*<td[^>]*>([^<]*)<\/td>\s*<\/tr>/gi;

    let match;
    while ((match = regex.exec(html)) !== null) {
        const codigo = limpiarTexto(match[1]);
        const nombre = limpiarTexto(match[2]);
        const correlativasRaw = limpiarTexto(match[3]);

        // Filtrar encabezados
        if (codigo && 
            !codigo.includes('Código') && 
            !codigo.includes('SEMESTRE') && 
            !codigo.includes('AÑO') &&
            nombre &&
            !nombre.includes('Nombre')) {

            materias.push({
                codigo: codigo,
                nombre: nombre,
                correlativasRaw: correlativasRaw
            });
        }
    }

    return {
        carrera: plan.nombre,
        materias: materias
    };
}

// 6. RESOLVER CORRELATIVAS (convertir códigos en nombres)
function resolverCorrelativas(materia, todasMaterias) {
    if (!materia.correlativasRaw || materia.correlativasRaw === "Ninguna") {
        return [];
    }

    // Separar códigos (pueden estar separados por /, -, o espacios)
    const codigosRaw = materia.correlativasRaw.split(/[\/\-\s]+/).filter(c => c.trim());

    const correlativasResueltas = codigosRaw.map(codigo => {
        const codigoLimpio = codigo.trim();

        // Buscar el nombre de la materia por su código
        const materiaCorrelativa = todasMaterias.find(m => m.codigo === codigoLimpio);

        if (materiaCorrelativa) {
            return {
                codigo: codigoLimpio,
                nombre: materiaCorrelativa.nombre
            };
        } else {
            // Si no encuentra el nombre, devuelve solo el código
            return {
                codigo: codigoLimpio,
                nombre: null
            };
        }
    });

    return correlativasResueltas;
}

// 7. CASO 1: BÚSQUEDA POR MATERIA ESPECÍFICA
if (busquedaMateria) {
    const resultados = [];

    todosLosPlanes.forEach(plan => {
        const planParsed = parsearPlanHTML(plan);

        planParsed.materias.forEach(materia => {
            if (normalizar(materia.nombre).includes(normalizar(busquedaMateria)) ||
                normalizar(materia.codigo).includes(normalizar(busquedaMateria))) {

                // Resolver correlativas
                const correlativas = resolverCorrelativas(materia, planParsed.materias);

                resultados.push({
                    carrera: planParsed.carrera,
                    codigo: materia.codigo,
                    nombre: materia.nombre,
                    correlativas: correlativas
                });
            }
        });
    });

    if (resultados.length === 0) {
        return `❌ No encontré "${query.materia}" en ningún plan.`;
    }

    // Formatear respuesta
    if (resultados.length === 1) {
        const m = resultados[0];

        if (m.correlativas.length === 0) {
            return `${m.nombre} (${m.codigo}) - ${m.carrera}\n\n✅ No tiene correlativas (materia de primer año).`;
        }

        const listaCorrelativas = m.correlativas.map(c => {
            if (c.nombre) {
                return `• ${c.nombre} (${c.codigo})`;
            } else {
                return `• ${c.codigo}`;
            }
        }).join('\n');

        return `${m.nombre} (${m.codigo}) - ${m.carrera}\n\nCorrelativas:\n${listaCorrelativas}`;

    } else {
        // Múltiples resultados (misma materia en diferentes carreras)
        const lista = resultados.map(m => {
            const correlativasTexto = m.correlativas.length === 0 
                ? "Sin correlativas" 
                : m.correlativas.map(c => c.nombre || c.codigo).join(', ');

            return `• ${m.carrera}: ${m.nombre} (${m.codigo})\n  Correlativas: ${correlativasTexto}`;
        }).join('\n\n');

        return `Encontré "${query.materia}" en ${resultados.length} planes:\n\n${lista}`;
    }
}

// 8. CASO 2: SIN BÚSQUEDA → LISTAR CARRERAS
if (!busquedaCarrera) {
    const listaCarreras = todosLosPlanes.map(p => `• ${p.nombre}`).join('\n');
    return `Carreras disponibles:\n\n${listaCarreras}\n\n💡 Para correlativas: especifica la materia.`;
}

// 9. CASO 3: BÚSQUEDA POR CARRERA
const busquedaNormalizada = normalizar(busquedaCarrera);

const planesEncontrados = todosLosPlanes.filter(p => {
    const nombreNormalizado = normalizar(p.nombre || "");
    return nombreNormalizado.includes(busquedaNormalizada);
});

if (planesEncontrados.length === 0) {
    const sugerencias = todosLosPlanes.map(p => `• ${p.nombre}`).join('\n');
    return `❌ No encontré "${query.carrera}".\n\nDisponibles:\n${sugerencias}`;
}

if (planesEncontrados.length > 1) {
    const opciones = planesEncontrados.map(p => `• ${p.nombre}`).join('\n');
    return `Encontré ${planesEncontrados.length} planes:\n\n${opciones}\n\n💡 Sé más específico.`;
}

// 10. DEVOLVER PLAN COMPLETO
const plan = parsearPlanHTML(planesEncontrados[0]);

const materiasResumen = plan.materias.slice(0, 10).map(m => {
    const correlativas = resolverCorrelativas(m, plan.materias);
    const correlativasTexto = correlativas.length === 0 
        ? "Ninguna" 
        : correlativas.map(c => c.codigo).join(', ');

    return `${m.codigo} - ${m.nombre} | Correlativas: ${correlativasTexto}`;
}).join('\n');

return `${plan.carrera}\n\nPrimeras 10 materias:\n${materiasResumen}\n\n💡 Total: ${plan.materias.length} materias.`;

