// 1. VALIDACIÓN
const slug = query?.slug;
if (!slug) return "❌ ERROR: No se especificó el slug de la materia.";

try {
  // 2. LLAMADA A LA API
  const response = await this.helpers.httpRequest({
    method: 'GET',
    url: `https://gestiondocente.info.unlp.edu.ar/api/v2/materias/${slug}/reservas.json`,
    json: true
  });

  // 3. EXTRAER RESERVAS
  const reservas = response._embedded?.reservas || [];

  if (reservas.length === 0) {
    return `ℹ️ No hay horarios confirmados para '${slug}' en este momento.`;
  }

  // 4. MAPEO DE DÍAS (la API devuelve números)
  const DIAS = {
    0: "Lunes",
    1: "Martes", 
    2: "Miércoles",
    3: "Jueves",
    4: "Viernes",
    5: "Sábado",
    6: "Domingo"
  };

  // 5. PROCESAR CADA RESERVA
  const horarios = reservas.map(r => {
    // Día de la semana
    const dia = DIAS[r.dia_semana] || "Día no especificado";

    // Horarios (la API usa hora_desde/hora_hasta, no hora_inicio/hora_fin)
    let horario = "Horario a confirmar";
    if (r.hora_desde && r.hora_hasta) {
      const desde = r.hora_desde.slice(0, 5); // "08:30:00-0300" → "08:30"
      const hasta = r.hora_hasta.slice(0, 5); // "12:00:00-0300" → "12:00"
      horario = `${desde} a ${hasta}`;
    }

    // Aula (está dentro de _embedded.aula)
    let aula = "Aula sin confirmar";
    if (r._embedded?.aula?.nombre) {
      aula = r._embedded.aula.nombre;
    }

    // Tipo de clase (está en _embedded.tipo_clase)
    let tipo = "Clase";
    if (r._embedded?.tipo_clase?.nombre) {
      tipo = r._embedded.tipo_clase.nombre;
    }

    // Período de validez (opcional pero útil)
    let periodo = "";
    if (r.fecha_desde && r.fecha_hasta) {
      periodo = `\n   📆 Válido: ${r.fecha_desde} al ${r.fecha_hasta}`;
    }

    return `🕒 **${dia} ${horario}**\n   📍 ${aula} (${tipo})${periodo}`;
  }).join("\n\n");

  // 6. RESPUESTA FINAL
  return `📅 HORARIOS Y AULAS CONFIRMADAS PARA ${slug.toUpperCase()}:\n\n${horarios}`;

} catch (error) {
  // Manejo de errores específico
  if (error.response?.status === 404) {
    return `❌ No existe la materia con slug '${slug}'. Verifica el nombre en consultar_materias.`;
  }

  const errorMsg = error.message || "Error desconocido";
  return `⚠️ Error al consultar horarios: ${errorMsg}`;
}

// 1. OBTENCIÓN Y NORMALIZACIÓN
// Como no tenemos lista de aulas, ayudamos a la IA convirtiendo "Aula 5" -> "aula-5"
let slug = query.slug;

if (!slug) return "ERROR: No llegó el identificador del aula.";

// Normalización técnica: minúsculas y espacios por guiones
const slugFinal = slug.toLowerCase().replace(/\s+/g, '-').trim();

// 2. FECHA DE HOY (Para filtrar y no traer historial viejo)
// Calculamos la fecha actual en formato YYYY-MM-DD para el parámetro 'desde'
const hoy = new Date().toISOString().split('T')[0];

try {
  // 3. LLAMADA A LA API
  // Usamos el filtro 'desde' para ver solo lo futuro/actual
  const response = await this.helpers.httpRequest({
    method: 'GET',
    url: `https://gestiondocente.info.unlp.edu.ar/api/v2/aulas/${slugFinal}/reservas.json`,
    qs: { desde: hoy }, 
    json: true
  });

  // 4. ESTRATEGIA DE LECTURA (HATEOAS vs Directo)
  const reservas = response._embedded?.reservas || response || [];

  if (!Array.isArray(reservas) || reservas.length === 0) {
    return `ℹ️ No encontré reservas registradas en el '${slugFinal}' a partir de hoy. Podría estar libre.`;
  }

  // 5. FORMATEO DE SALIDA
  // Ordenamos por día/hora para que quede cronológico
  const lista = reservas
    .slice(0, 10) // Limitamos a 10 eventos para no llenar la pantalla
    .map(r => {
        const dia = r.dia || r.fecha || "Fecha a confirmar";
        const hora = (r.hora_inicio && r.hora_fin) 
                     ? `${r.hora_inicio.slice(0,5)} a ${r.hora_fin.slice(0,5)}` 
                     : "Horario desc.";

        // Intentamos sacar el nombre de la materia o evento
        let evento = "Evento reservado";
        if (r.materia) {
            evento = typeof r.materia === 'object' ? r.materia.nombre : r.materia;
        } else if (r.evento) {
            evento = r.evento;
        }

        return `📍 **${dia} [${hora}]**\n   🎓 ${evento}`;
    }).join("\n\n");

  return `📅 OCUPACIÓN DEL ${slugFinal.toUpperCase()}:\n\n${lista}`;

} catch (error) {
  return `ERROR 404: No pude encontrar el aula '${slugFinal}'. Verifica si el número es correcto (ej: Aula 5, Aula Magna).`;
}

