// 1. OBTENER PARÁMETROS
const busqueda = query.busqueda || query.query || "";
const documentoId = query.document_id || null;

// 2. VALIDACIÓN
if (!busqueda || busqueda.trim().length === 0) {
  return "❌ ERROR: No especificaste qué buscar.";
}

// 3. PREPARAR PAYLOAD
const payload = {
  query: busqueda.trim()
};

// Si se especifica documento, agregarlo al filtro
if (documentoId) {
  payload.document_id = parseInt(documentoId);
}

try {
  // 4. LLAMADA AL ENDPOINT FLASK
  const response = await this.helpers.httpRequest({
    method: 'POST',
    url: 'http://192.168.1.11:5000/document/api/search',
    json: true,
    body: payload
  });

  // 5. VALIDACIÓN DE RESPUESTA
  if (!response.resultados || response.resultados.length === 0) {
    return `❌ No encontré resultados para "${busqueda}"${documentoId ? ` en el documento ${documentoId}` : ''}.`;
  }

  // 6. FORMATEO DE RESPUESTA
  const filtroTexto = documentoId ? ` (filtrado por documento ${documentoId})` : '';
  const lista = response.resultados.map((r, idx) => {
    const porcentaje = Math.round(r.score * 100);
    const archivo = r.archivo ? `📄 ${r.archivo}` : '';
    const seccion = r.seccion ? `📌 ${r.seccion}` : '';

    return `${idx + 1}. **Relevancia: ${porcentaje}%**\n   ${seccion}\n   ${archivo}\n   "${r.texto}"\n   📍 Chunk ${r.chunk_index}`;
  }).join('\n\n---\n\n');

  return `🔍 RESULTADOS DE BÚSQUEDA${filtroTexto}:\n\n${lista}\n\n💡 Total: ${response.total_resultados} resultados encontrados.`;

} catch (error) {
  const errorMsg = error.response?.data?.error || error.message || 'Error desconocido';
  return `⚠️ Error en la búsqueda: ${errorMsg}`;
}

